{
  "name": "SAAD (صاد) - Pharmacy Locator",
  "description": "A clean, Arabic RTL pharmacy locator web application to search for medicines in local pharmacies using Supabase."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { Search, Pill, MapPin, Phone, Clock, AlertCircle } from 'lucide-react';
import { searchMedicines } from './services/searchService';
import { SearchResult } from './types';

// Components
import { Header } from './components/Header';
import { SearchInput } from './components/SearchInput';
import { ResultCard } from './components/ResultCard';

export default function App() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = useCallback(async () => {
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    setHasSearched(true);
    setResults([]);

    try {
      const data = await searchMedicines(query);
      setResults(data);
    } catch (err) {
      console.error(err);
      setError('حدث خطأ أثناء البحث. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  }, [query]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearch();
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-12 max-w-3xl">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-extrabold text-primary-800 mb-4">
            ابحث عن دوائك بسهولة
          </h1>
          <p className="text-gray-500 text-lg">
            دليل صيدليات "صاد" يساعدك في العثور على الأدوية المتوفرة في الصيدليات القريبة منك.
          </p>
        </div>

        <section className="mb-12">
          <SearchInput
            value={query}
            onChange={setQuery}
            onSearch={handleSearch}
            loading={loading}
            onKeyDown={handleKeyDown}
          />
        </section>

        <section aria-live="polite">
          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-3 mb-6">
              <AlertCircle className="w-5 h-5" />
              <span>{error}</span>
            </div>
          )}

          {loading && (
            <div className="flex justify-center items-center py-12">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
            </div>
          )}

          {!loading && hasSearched && results.length === 0 && !error && (
            <div className="text-center py-12 bg-white rounded-2xl shadow-sm border border-gray-100">
              <div className="inline-flex items-center justify-center w-16 h-16 bg-gray-100 rounded-full mb-4">
                <Search className="w-8 h-8 text-gray-400" />
              </div>
              <h3 className="text-xl font-bold text-gray-700 mb-2">لم يتم العثور على نتائج</h3>
              <p className="text-gray-500">جرب البحث بكلمات مختلفة أو تأكد من اسم الدواء.</p>
            </div>
          )}

          <div className="grid gap-4 md:grid-cols-1">
            {results.map((item) => (
              <ResultCard key={item.id} data={item} />
            ))}
          </div>
        </section>
      </main>

      <footer className="bg-white border-t border-gray-100 py-8 mt-auto">
        <div className="container mx-auto px-4 text-center text-gray-400 text-sm">
          <p>© {new Date().getFullYear()} صاد - جميع الحقوق محفوظة</p>
        </div>
      </footer>
    </div>
  );
}

export interface Pharmacy {
  id: string;
  name: string;
  address: string;
  phone: string;
  is_open: boolean;
}

export interface Medicine {
  id: string;
  trade_name: string;
  scientific_name: string;
}

export interface InventoryItem {
  id: string;
  pharmacy_id: string;
  medicine_id: string;
  price: number;
  quantity: number;
}

// Joined result interface for the UI
export interface SearchResult {
  id: string; // Inventory ID
  price: number;
  quantity: number;
  medicines: {
    trade_name: string;
    scientific_name: string;
  } | null; // Nullable because of join structure in Supabase response types usually
  pharmacies: {
    name: string;
    address: string;
    phone: string;
    is_open: boolean;
  } | null;
}

import { createClient } from '@supabase/supabase-js';

// NOTE: In a real Next.js app, these would be process.env.NEXT_PUBLIC_SUPABASE_URL
// For this React SPA generation, we assume standard env vars are provided or injected.
const supabaseUrl = process.env.REACT_APP_SUPABASE_URL || 'https://placeholder-url.supabase.co';
const supabaseAnonKey = process.env.REACT_APP_SUPABASE_ANON_KEY || 'placeholder-key';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export const isSupabaseConfigured = () => {
  return (
    process.env.REACT_APP_SUPABASE_URL &&
    process.env.REACT_APP_SUPABASE_ANON_KEY
  );
};

import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { SearchResult } from '../types';

/**
 * Searches for medicines in the inventory matching the trade name.
 * Uses a partial case-insensitive match (ILIKE).
 */
export const searchMedicines = async (queryTerm: string): Promise<SearchResult[]> => {
  // 1. If Supabase is not configured (e.g. initial run without keys), return mock data for demo purposes.
  if (!isSupabaseConfigured()) {
    console.warn("Supabase keys missing. Returning mock data.");
    return mockSearch(queryTerm);
  }

  // 2. Perform the actual query
  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicines!inner (
        trade_name,
        scientific_name
      ),
      pharmacies!inner (
        name,
        address,
        phone,
        is_open
      )
    `)
    // We filter based on the joined medicine's trade_name
    .ilike('medicines.trade_name', `%${queryTerm}%`);

  if (error) {
    throw error;
  }

  return data as unknown as SearchResult[];
};

// --- Mock Data Service (Fallback) ---

const mockSearch = async (term: string): Promise<SearchResult[]> => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  const allMockData: SearchResult[] = [
    {
      id: '1',
      price: 15.50,
      quantity: 12,
      medicines: {
        trade_name: 'Panadol Extra',
        scientific_name: 'Paracetamol + Caffeine'
      },
      pharmacies: {
        name: 'صيدلية النهضة',
        address: 'شارع الملك فهد، الرياض',
        phone: '011-444-5555',
        is_open: true
      }
    },
    {
      id: '2',
      price: 22.00,
      quantity: 5,
      medicines: {
        trade_name: 'Panadol Cold & Flu',
        scientific_name: 'Paracetamol + Phenylephrine'
      },
      pharmacies: {
        name: 'صيدلية المجتمع',
        address: 'حي العليا، الرياض',
        phone: '011-222-3333',
        is_open: false
      }
    },
    {
      id: '3',
      price: 45.00,
      quantity: 20,
      medicines: {
        trade_name: 'Brufen 600mg',
        scientific_name: 'Ibuprofen'
      },
      pharmacies: {
        name: 'صيدلية الدواء',
        address: 'طريق الدمام، الخبر',
        phone: '013-888-9999',
        is_open: true
      }
    }
  ];

  return allMockData.filter(item => 
    item.medicines?.trade_name.toLowerCase().includes(term.toLowerCase())
  );
};

