import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { SearchResult } from '../types';

/**
 * Searches for medicines in the inventory matching the trade name or scientific name.
 * Uses a partial case-insensitive match (ILIKE).
 */
export const searchMedicines = async (queryTerm: string): Promise<SearchResult[]> => {
  // 1. If Supabase is not configured (e.g. initial run without keys), return mock data for demo purposes.
  if (!isSupabaseConfigured()) {
    console.warn("Supabase keys missing. Returning mock data.");
    return mockSearch(queryTerm);
  }

  // 2. Perform the actual query
  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicines!inner (
        trade_name,
        scientific_name
      ),
      pharmacies!inner (
        name,
        address,
        phone,
        is_open
      )
    `)
    // Search in both trade_name and scientific_name of the joined medicines table
    .or(`trade_name.ilike.%${queryTerm}%,scientific_name.ilike.%${queryTerm}%`, { foreignTable: 'medicines' });

  if (error) {
    throw error;
  }

  return data as unknown as SearchResult[];
};

// --- Mock Data Service (Fallback) ---

const mockSearch = async (term: string): Promise<SearchResult[]> => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  const allMockData: SearchResult[] = [
    {
      id: '1',
      price: 15.50,
      quantity: 12,
      medicines: {
        trade_name: 'Panadol Extra',
        scientific_name: 'Paracetamol + Caffeine'
      },
      pharmacies: {
        name: 'صيدلية النهضة',
        address: 'شارع الملك فهد، الرياض',
        phone: '011-444-5555',
        is_open: true
      }
    },
    {
      id: '2',
      price: 22.00,
      quantity: 5,
      medicines: {
        trade_name: 'Panadol Cold & Flu',
        scientific_name: 'Paracetamol + Phenylephrine'
      },
      pharmacies: {
        name: 'صيدلية المجتمع',
        address: 'حي العليا، الرياض',
        phone: '011-222-3333',
        is_open: false
      }
    },
    {
      id: '3',
      price: 45.00,
      quantity: 20,
      medicines: {
        trade_name: 'Brufen 600mg',
        scientific_name: 'Ibuprofen'
      },
      pharmacies: {
        name: 'صيدلية الدواء',
        address: 'طريق الدمام، الخبر',
        phone: '013-888-9999',
        is_open: true
      }
    }
  ];

  const lowerTerm = term.toLowerCase();

  return allMockData.filter(item => {
    const tradeName = item.medicines?.trade_name.toLowerCase() || '';
    const scientificName = item.medicines?.scientific_name.toLowerCase() || '';

    return tradeName.includes(lowerTerm) || scientificName.includes(lowerTerm);
  });
};

