import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { SearchResult } from '../types';

/**
 * Searches for medicines in the inventory matching the trade name or scientific name.
 * Uses a partial case-insensitive match (ILIKE).
 */
export const searchMedicines = async (queryTerm: string): Promise<SearchResult[]> => {
  const term = queryTerm.trim();

  // 1. If Supabase is not configured (e.g. initial run without keys), return mock data for demo purposes.
  if (!isSupabaseConfigured()) {
    console.warn("Supabase keys missing. Returning mock data.");
    return mockSearch(term);
  }

  // 2. Perform the actual query
  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicines!inner (
        trade_name,
        scientific_name
      ),
      pharmacies!inner (
        name,
        address,
        phone,
        is_open
      )
    `)
    // Search in both trade_name and scientific_name of the joined medicines table
    .or(`trade_name.ilike.%${term}%,scientific_name.ilike.%${term}%`, { foreignTable: 'medicines' });

  if (error) {
    throw error;
  }

  return data as unknown as SearchResult[];
};

// --- Mock Data Service (Fallback) ---

const mockSearch = async (term: string): Promise<SearchResult[]> => {
  // Simulate network delay
