import { getPharmacyInventory, addInventoryItem, updateInventoryItem, deleteInventoryItem } from '../services/pharmacyService';
import { InventoryModal } from './InventoryModal';

interface DashboardPageProps {
  user: User;
}

export const DashboardPage: React.FC<DashboardPageProps> = ({ user }) => {
  const [inventory, setInventory] = useState<DashboardInventoryItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<DashboardInventoryItem | undefined>(undefined);

  useEffect(() => {
    loadInventory();
  }, [user.pharmacyId]);

  const loadInventory = async () => {
    try {
      const data = await getPharmacyInventory(user.pharmacyId);
      setInventory(data);
    } catch (error) {
      console.error('Error loading inventory:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddClick = () => {
    setEditingItem(undefined);
    setIsModalOpen(true);
  };

  const handleEditClick = (item: DashboardInventoryItem) => {
    setEditingItem(item);
    setIsModalOpen(true);
  };

  const handleDeleteClick = async (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدواء من المخزون؟')) {
      try {
        await deleteInventoryItem(id);
        setInventory(prev => prev.filter(item => item.id !== id));
      } catch (error) {
        console.error('Error deleting item:', error);
      }
    }
  };

  const handleSave = async (data: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => {
    if (editingItem) {
      // Update
      await updateInventoryItem(editingItem.id, data);
      setInventory(prev => prev.map(item => 
        item.id === editingItem.id ? { ...item, ...data } : item
      ));
    } else {
      // Add
      const newItem = await addInventoryItem(user.pharmacyId, data);
      // We cast the return type for simplicity here as our mock service returns a full item
      setInventory(prev => [newItem as DashboardInventoryItem, ...prev]);
    }
  };

  const outOfStockCount = inventory.filter(i => i.quantity === 0).length;

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Pharmacy Header Card */}
      <div className="bg-gradient-to-l from-primary-800 to-primary-600 rounded-3xl p-8 text-white shadow-lg">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div>
            <h1 className="text-3xl font-bold mb-2">لوحة التحكم - {user.name}</h1>
            <div className="flex items-center gap-2 text-primary-100">
              <MapPin size={18} />
              <span>فرع الرياض - حي الملز</span>
            </div>
          </div>
          <div className="flex gap-4">
             <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 flex items-center gap-3 border border-white/10">
               <div className="bg-white/20 p-2 rounded-lg">
                 <Package size={24} />
               </div>
               <div>
                 <p className="text-xs text-primary-100 font-bold">إجمالي الأدوية</p>
                 <p className="text-2xl font-black">{inventory.length}</p>
               </div>
             </div>
             <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 flex items-center gap-3 border border-white/10">
               <div className="bg-red-500/20 p-2 rounded-lg text-red-200">
                 <AlertTriangle size={24} />
               </div>
               <div>
                 <p className="text-xs text-primary-100 font-bold">نفذت الكمية</p>
                 <p className="text-2xl font-black">{outOfStockCount}</p>
               </div>
             </div>
          </div>
        </div>
      </div>

      {/* Inventory Section */}
      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex flex-wrap gap-4 items-center justify-between">
          <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            <Package className="text-primary-600" />
            إدارة المخزون
          </h2>
          <button
            onClick={handleAddClick}
            className="flex items-center gap-2 bg-primary-600 hover:bg-primary-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all shadow-md shadow-primary-600/20"
          >
            <Plus size={20} />
            إضافة دواء
          </button>
        </div>

        {loading ? (
          <div className="p-12 text-center text-gray-400">جاري تحميل البيانات...</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-gray-50/50 text-gray-500 text-sm">
                <tr>
                  <th className="px-6 py-4 font-bold rounded-tr-3xl">اسم الدواء</th>
                  <th className="px-6 py-4 font-bold">الاسم العلمي</th>
                  <th className="px-6 py-4 font-bold">السعر</th>
                  <th className="px-6 py-4 font-bold">الكمية</th>
                  <th className="px-6 py-4 font-bold">الحالة</th>
                  <th className="px-6 py-4 font-bold rounded-tl-3xl">إجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {inventory.length === 0 ? (
                   <tr>
                     <td colSpan={6} className="px-6 py-12 text-center text-gray-400">
                       لا توجد أدوية في المخزون حالياً
                     </td>
                   </tr>
                ) : (
                  inventory.map((item) => (
                    <tr key={item.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-6 py-4 font-bold text-gray-800">{item.trade_name}</td>
                      <td className="px-6 py-4 text-gray-500">{item.scientific_name}</td>
                      <td className="px-6 py-4 font-medium text-primary-700">{item.price} ر.س</td>
                      <td className="px-6 py-4 font-medium">{item.quantity}</td>
                      <td className="px-6 py-4">
                        {item.quantity > 0 ? (
                          <span className="inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold bg-green-50 text-green-700">
                            متوفر
                          </span>
                        ) : (
                          <span className="inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold bg-red-50 text-red-700">
                            غير متوفر
                          </span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <button 
                            onClick={() => handleEditClick(item)}
                            className="p-2 hover:bg-blue-50 text-blue-600 rounded-lg transition-colors"
                            title="تعديل"
                          >
                            <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={() => handleDeleteClick(item.id)}
                            className="p-2 hover:bg-red-50 text-red-600 rounded-lg transition-colors"
                            title="حذف"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <InventoryModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSave}
        initialData={editingItem}
      />
    </div>
  );
};

