import React, { useState, useCallback } from 'react';
import { Search, AlertCircle } from 'lucide-react';
import { searchMedicines } from './services/searchService';
import { SearchResult, User } from './types';

// Components
import { Header } from './components/Header';
import { SearchInput } from './components/SearchInput';
import { ResultCard } from './components/ResultCard';
import { LoginPage } from './components/LoginPage';
import { DashboardPage } from './components/DashboardPage';

type ViewState = 'search' | 'login' | 'dashboard';

export default function App() {
  const [currentView, setCurrentView] = useState<ViewState>('search');
  const [user, setUser] = useState<User | null>(null);

  // Search State
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = useCallback(async () => {
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    setHasSearched(true);
    setResults([]);

    try {
      const data = await searchMedicines(query);
      setResults(data);
    } catch (err) {
      console.error(err);
      setError('حدث خطأ أثناء البحث. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  }, [query]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearch();
    }
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentView('search');
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50/50">
      <Header 
        onLoginClick={() => setCurrentView('login')}
        onLogoutClick={handleLogout}
        onLogoClick={() => setCurrentView(user ? 'dashboard' : 'search')}
        isLoggedIn={!!user}
        showLoginBtn={currentView === 'search'}
      />

      <main className="flex-grow container mx-auto px-4 py-12 max-w-4xl">
        {currentView === 'login' ? (
          <LoginPage 
            onBack={() => setCurrentView('search')} 
            onLoginSuccess={handleLoginSuccess}
          />
        ) : currentView === 'dashboard' && user ? (
          <DashboardPage user={user} />
        ) : (
          <>
            <div className="text-center mb-10">
              <h1 className="text-4xl font-extrabold text-primary-800 mb-4">
                ابحث عن دوائك بسهولة
              </h1>
              <p className="text-gray-500 text-lg">
                دليل صيدليات "صاد" يساعدك في العثور على الأدوية المتوفرة في الصيدليات القريبة منك.
              </p>
            </div>

            <section className="mb-12">
              <SearchInput
                value={query}
                onChange={setQuery}
                onSearch={handleSearch}
                loading={loading}
                onKeyDown={handleKeyDown}
              />
            </section>

            <section aria-live="polite">
              {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-3 mb-6">
                  <AlertCircle className="w-5 h-5" />
                  <span>{error}</span>
                </div>
              )}

              {loading && (
                <div className="flex justify-center items-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
                </div>
              )}

              {!loading && hasSearched && results.length === 0 && !error && (
                <div className="text-center py-12 bg-white rounded-2xl shadow-sm border border-gray-100">
                  <div className="inline-flex items-center justify-center w-16 h-16 bg-gray-100 rounded-full mb-4">
                    <Search className="w-8 h-8 text-gray-400" />
                  </div>
                  <h3 className="text-xl font-bold text-gray-700 mb-2">لم يتم العثور على نتائج</h3>
                  <p className="text-gray-500">جرب البحث بكلمات مختلفة أو تأكد من اسم الدواء.</p>
                </div>
              )}

              <div className="grid gap-4 md:grid-cols-1">
                {results.map((item) => (
                  <ResultCard key={item.id} data={item} />
                ))}
              </div>
            </section>
          </>
        )}
      </main>

      <footer className="bg-white border-t border-gray-100 py-8 mt-auto">
        <div className="container mx-auto px-4 text-center text-gray-400 text-sm">
          <p>© {new Date().getFullYear()} صاد - جميع الحقوق محفوظة</p>
        </div>
      </footer>
    </div>
  );
}

-- Step 1: Create Tables

-- Pharmacies Table (Updated with email for login)
CREATE TABLE pharmacies (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL,
  address TEXT NOT NULL,
  phone TEXT,
  email TEXT UNIQUE NOT NULL, -- Added for login
  password TEXT NOT NULL,     -- Added for login (In real apps, use Supabase Auth)
  is_open BOOLEAN DEFAULT true,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW())
);

-- Medicines Table
CREATE TABLE medicines (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  trade_name TEXT NOT NULL,
  scientific_name TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW())
);

-- Inventory Table (Relationship)
CREATE TABLE inventory (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  pharmacy_id UUID REFERENCES pharmacies(id) ON DELETE CASCADE,
  medicine_id UUID REFERENCES medicines(id) ON DELETE CASCADE,
  price DECIMAL(10, 2) NOT NULL,
  quantity INTEGER NOT NULL DEFAULT 0,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc', NOW()),

  -- Ensure unique pharmacy-medicine pair
  UNIQUE(pharmacy_id, medicine_id)
);

-- Step 2: Enable Row Level Security (RLS)
ALTER TABLE pharmacies ENABLE ROW LEVEL SECURITY;
ALTER TABLE medicines ENABLE ROW LEVEL SECURITY;
ALTER TABLE inventory ENABLE ROW LEVEL SECURITY;

