CREATE POLICY "Enable read access for all users" ON pharmacies FOR SELECT USING (true);
CREATE POLICY "Enable read access for all users" ON medicines FOR SELECT USING (true);
CREATE POLICY "Enable read access for all users" ON inventory FOR SELECT USING (true);

-- Allow anyone to insert/update (In production, you'd restrict this to authenticated users)
CREATE POLICY "Enable insert for all users" ON pharmacies FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable insert for all users" ON medicines FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable insert for all users" ON inventory FOR INSERT WITH CHECK (true);
CREATE POLICY "Enable update for all users" ON inventory FOR UPDATE USING (true);
CREATE POLICY "Enable delete for all users" ON inventory FOR DELETE USING (true);


