import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { DashboardInventoryItem, User } from '../types';

// --- MOCK DATA FALLBACK (Used only if Supabase is NOT connected) ---
let mockInventory: DashboardInventoryItem[] = [
  { id: '1', medicine_id: 'm1', trade_name: 'Panadol Extra', scientific_name: 'Paracetamol + Caffeine', price: 15.50, quantity: 12 },
  { id: '2', medicine_id: 'm2', trade_name: 'Brufen 600mg', scientific_name: 'Ibuprofen', price: 24.00, quantity: 45 },
];

// --- REAL SUPABASE IMPLEMENTATION ---

export const pharmacyLogin = async (email: string): Promise<User> => {
  if (!isSupabaseConfigured()) {
    // Mock Fallback
    await new Promise(resolve => setTimeout(resolve, 1000));
    return { id: 'u1', pharmacyId: 'p1', email: email, name: 'صيدلية تجريبية (Mock)' };
  }

  // Simple query-based login (In production, use supabase.auth.signInWithPassword)
  const { data, error } = await supabase
    .from('pharmacies')
    .select('*')
    .eq('email', email)
    .single();

  if (error || !data) {
    throw new Error('Invalid credentials');
  }

  // Mapping the database result to our User type
  return {
    id: data.id,
    pharmacyId: data.id, // In this simple schema, the user IS the pharmacy
    email: data.email,
    name: data.name
  };
};

export const getPharmacyInventory = async (pharmacyId: string): Promise<DashboardInventoryItem[]> => {
  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return [...mockInventory];
  }

  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicine_id,
      medicines (
        trade_name,
        scientific_name
      )
    `)
    .eq('pharmacy_id', pharmacyId);

  if (error) throw error;

  return data.map((item: any) => ({
    id: item.id,
    medicine_id: item.medicine_id,
    trade_name: item.medicines?.trade_name,
    scientific_name: item.medicines?.scientific_name,
    price: item.price,
    quantity: item.quantity
  }));
};

export const addInventoryItem = async (pharmacyId: string, item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => {
  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 600));
    const newItem = { ...item, id: Math.random().toString(), medicine_id: Math.random().toString() };
    mockInventory = [newItem, ...mockInventory];
    return newItem;
  }

  // 1. Check if medicine exists, or create it
  // We try to find a medicine with the same trade_name (case insensitive matching would be better in prod)
  let { data: medicine } = await supabase
    .from('medicines')
    .select('id')
    .eq('trade_name', item.trade_name)
    .maybeSingle();

  if (!medicine) {
    const { data: newMedicine, error: createError } = await supabase
      .from('medicines')
      .insert({
        trade_name: item.trade_name,
        scientific_name: item.scientific_name
      })
      .select()
      .single();

    if (createError) throw createError;
    medicine = newMedicine;
  }

  // 2. Add to inventory
  if (medicine) {
    const { data: newInventory, error: invError } = await supabase
      .from('inventory')
      .insert({
        pharmacy_id: pharmacyId,
        medicine_id: medicine.id,
        price: item.price,
        quantity: item.quantity
      })
      .select(`
        id,
        price,
        quantity,
        medicine_id,
        medicines (
          trade_name,
          scientific_name
        )
      `)
      .single();

    if (invError) throw invError;

    // Return formatted item
    const formattedItem: DashboardInventoryItem = {
      id: newInventory.id,
      medicine_id: newInventory.medicine_id,
      trade_name: (newInventory as any).medicines?.trade_name,
      scientific_name: (newInventory as any).medicines?.scientific_name,
      price: newInventory.price,
      quantity: newInventory.quantity
    };
    return formattedItem;
  }

  throw new Error("Failed to create medicine reference");
};

export const updateInventoryItem = async (id: string, updates: Partial<DashboardInventoryItem>) => {
  if (!isSupabaseConfigured()) {
    mockInventory = mockInventory.map(item => item.id === id ? { ...item, ...updates } : item);
    return;
  }

  const { error } = await supabase
    .from('inventory')
    .update({
      price: updates.price,
      quantity: updates.quantity
    })
    .eq('id', id);

  if (error) throw error;
};

export const deleteInventoryItem = async (id: string) => {
  if (!isSupabaseConfigured()) {
    mockInventory = mockInventory.filter(item => item.id !== id);
    return;
  }

  const { error } = await supabase
    .from('inventory')
    .delete()
    .eq('id', id);

  if (error) throw error;
};

import React, { useState, useEffect } from 'react';
import { X, Save, AlertCircle } from 'lucide-react';
import { DashboardInventoryItem } from '../types';

interface InventoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => Promise<void>;
  initialData?: DashboardInventoryItem;
}

export const InventoryModal: React.FC<InventoryModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [tradeName, setTradeName] = useState('');
  const [scientificName, setScientificName] = useState('');
  const [price, setPrice] = useState('');
  const [quantity, setQuantity] = useState('');
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  useEffect(() => {
    if (initialData) {
      setTradeName(initialData.trade_name);
      setScientificName(initialData.scientific_name);
      setPrice(initialData.price.toString());
      setQuantity(initialData.quantity.toString());
      setErrors({});
    } else {
      setTradeName('');
      setScientificName('');
      setPrice('');
      setQuantity('');
      setErrors({});
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const validate = (): boolean => {
    const newErrors: { [key: string]: string } = {};
    let isValid = true;

    if (!tradeName.trim()) {
      newErrors.tradeName = 'الاسم التجاري مطلوب';
      isValid = false;
    }

    if (!scientificName.trim()) {
      newErrors.scientificName = 'الاسم العلمي مطلوب';
      isValid = false;
    }

    const priceNum = parseFloat(price);
    if (!price || isNaN(priceNum) || priceNum <= 0) {
      newErrors.price = 'السعر يجب أن يكون رقماً أكبر من 0';
      isValid = false;
    }

    const qtyNum = parseFloat(quantity);
    if (!quantity || isNaN(qtyNum) || qtyNum < 0 || !Number.isInteger(qtyNum)) {
      newErrors.quantity = 'الكمية يجب أن تكون رقماً صحيحاً غير سالب';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) return;

    setLoading(true);
    try {
      await onSave({
        trade_name: tradeName,
        scientific_name: scientificName,
        price: parseFloat(price),
        quantity: parseInt(quantity, 10)
      });
      onClose();
    } catch (error) {
      console.error(error);
      alert('حدث خطأ أثناء الحفظ. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-xl overflow-hidden transform transition-all scale-100">
        <div className="flex items-center justify-between p-6 border-b border-gray-100 bg-gray-50/50">
          <h3 className="text-xl font-bold text-gray-800">
            {initialData ? 'تعديل الدواء' : 'إضافة دواء جديد'}
          </h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-gray-500">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4" noValidate>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">الاسم التجاري</label>
            <input
              type="text"
              disabled={!!initialData} // Disable name edit if updating inventory only
              value={tradeName}
              onChange={(e) => {
                setTradeName(e.target.value);
                if (errors.tradeName) setErrors({...errors, tradeName: ''});
              }}
              className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none disabled:opacity-60 transition-all ${
                errors.tradeName ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
              }`}
              placeholder="مثال: Panadol Extra"
            />
            {errors.tradeName && (
              <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                <AlertCircle size={12} />
                {errors.tradeName}
              </p>
            )}
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">الاسم العلمي</label>
            <input
              type="text"
              disabled={!!initialData}
              value={scientificName}
              onChange={(e) => {
                setScientificName(e.target.value);
                if (errors.scientificName) setErrors({...errors, scientificName: ''});
              }}
              className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none disabled:opacity-60 transition-all ${
                errors.scientificName ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
              }`}
              placeholder="مثال: Paracetamol"
            />
            {errors.scientificName && (
              <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                <AlertCircle size={12} />
                {errors.scientificName}
              </p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">السعر (ر.س)</label>
              <input
                type="number"
                step="0.01"
                min="0.01"
                value={price}
                onChange={(e) => {
                  setPrice(e.target.value);
                  if (errors.price) setErrors({...errors, price: ''});
                }}
                className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none transition-all ${
                  errors.price ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
                }`}
                placeholder="0.00"
              />
              {errors.price && (
                <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                  <AlertCircle size={12} />
                  {errors.price}
                </p>
              )}
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">الكمية</label>
              <input
                type="number"
                min="0"
                step="1"
                value={quantity}
                onChange={(e) => {
                  setQuantity(e.target.value);
                  if (errors.quantity) setErrors({...errors, quantity: ''});
                }}
                className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none transition-all ${
                  errors.quantity ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
                }`}
                placeholder="0"
              />
              {errors.quantity && (
                <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                  <AlertCircle size={12} />
                  {errors.quantity}
                </p>
              )}
            </div>
          </div>

          <div className="pt-4">
            <button
              type="submit"
              disabled={loading}
              className="w-full py-3.5 px-4 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-xl transition-all shadow-md shadow-primary-600/20 flex items-center justify-center gap-2 disabled:opacity-70 disabled:shadow-none"
            >
              {loading ? (
                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
              ) : (
                <>
                  <Save size={18} />
                  <span>حفظ التغييرات</span>
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Search, AlertCircle } from 'lucide-react';
import { searchMedicines } from './services/searchService';
import { SearchResult, User } from './types';

// Components
import { Header } from './components/Header';
import { SearchInput } from './components/SearchInput';
import { ResultCard } from './components/ResultCard';
import { LoginPage } from './components/LoginPage';
import { DashboardPage } from './components/DashboardPage';

type ViewState = 'search' | 'login' | 'dashboard';

export default function App() {
  const [currentView, setCurrentView] = useState<ViewState>('search');
  const [user, setUser] = useState<User | null>(null);

  // Search State
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = useCallback(async () => {
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    setHasSearched(true);
    setResults([]);

    try {
      const data = await searchMedicines(query);
      setResults(data);
    } catch (err) {
      console.error(err);
      setError('حدث خطأ أثناء البحث. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  }, [query]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearch();
    }
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentView('search');
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50/50">
      <Header 
        onLoginClick={() => setCurrentView('login')}
        onLogoutClick={handleLogout}
        onLogoClick={() => setCurrentView(user ? 'dashboard' : 'search')}
        isLoggedIn={!!user}
        showLoginBtn={currentView === 'search'}
      />

      <main className="flex-grow container mx-auto px-4 py-12 max-w-4xl">
        {currentView === 'login' ? (
          <LoginPage 
            onBack={() => setCurrentView('search')} 
            onLoginSuccess={handleLoginSuccess}
          />
        ) : currentView === 'dashboard' && user ? (
          <DashboardPage user={user} />
        ) : (
          <>
            <div className="text-center mb-10">
              <h1 className="text-4xl font-extrabold text-primary-800 mb-4">
                ابحث عن دوائك بسهولة
              </h1>
              <p className="text-gray-500 text-lg">
                دليل صيدليات "صاد" يساعدك في العثور على الأدوية المتوفرة في الصيدليات القريبة منك.
              </p>
            </div>

            <section className="mb-12">
              <SearchInput
                value={query}
                onChange={setQuery}
                onSearch={handleSearch}
                loading={loading}
                onKeyDown={handleKeyDown}
              />
            </section>

            <section aria-live="polite">
              {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-3 mb-6">
                  <AlertCircle className="w-5 h-5" />
                  <span>{error}</span>
                </div>
              )}

              {loading && (
                <div className="flex justify-center items-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
                </div>
              )}

              {!loading && hasSearched && results.length === 0 && !error && (
                <div className="text-center py-16 bg-white rounded-3xl shadow-sm border border-gray-100 animate-in fade-in zoom-in duration-300">
                  <div className="inline-flex items-center justify-center w-20 h-20 bg-gray-50 rounded-full mb-6 relative">
                    <Search className="w-10 h-10 text-gray-300" />
                    <div className="absolute -bottom-1 -right-1 bg-red-50 text-red-500 rounded-full p-1.5 border-2 border-white">
                      <AlertCircle size={16} />
                    </div>
                  </div>
                  <h3 className="text-2xl font-bold text-gray-800 mb-3">عذراً، لم نجد نتائج لبحثك</h3>
                  <p className="text-gray-500 text-lg max-w-md mx-auto mb-6">
                    تأكد من كتابة اسم الدواء بشكل صحيح، أو جرب البحث بالاسم العلمي.
                  </p>
                  <button 
                    onClick={() => {
                      setQuery('');
                      const input = document.querySelector('input');
                      if (input) input.focus();
                    }}
                    className="text-primary-600 font-bold hover:text-primary-700 hover:underline"
                  >
                    مسح البحث والمحاولة مجدداً
                  </button>
                </div>
              )}

              <div className="grid gap-4 md:grid-cols-1">
                {results.map((item) => (
                  <ResultCard key={item.id} data={item} />
                ))}
              </div>
            </section>
          </>
        )}
      </main>

      <footer className="bg-white border-t border-gray-100 py-8 mt-auto">
        <div className="container mx-auto px-4 text-center text-gray-400 text-sm">
          <p>© {new Date().getFullYear()} صاد - جميع الحقوق محفوظة</p>
        </div>
      </footer>
    </div>
  );
}

