import { supabase, isSupabaseConfigured } from '../lib/supabase';
import { DashboardInventoryItem, User } from '../types';

// --- MOCK DATA FALLBACK (Used only if Supabase is NOT connected) ---
let mockInventory: DashboardInventoryItem[] = [
  { id: '1', medicine_id: 'm1', trade_name: 'Panadol Extra', scientific_name: 'Paracetamol + Caffeine', price: 15.50, quantity: 12 },
  { id: '2', medicine_id: 'm2', trade_name: 'Brufen 600mg', scientific_name: 'Ibuprofen', price: 24.00, quantity: 45 },
];

const logConnectionStatus = () => {
  if (!isSupabaseConfigured()) {
    console.warn('⚠️ Supabase is NOT configured. Using mock data. Check your .env file and restart the server.');
  } else {
    console.log('✅ Supabase connected.');
  }
};

// --- REAL SUPABASE IMPLEMENTATION ---

export const pharmacyLogin = async (email: string): Promise<User> => {
  logConnectionStatus();

  if (!isSupabaseConfigured()) {
    // Mock Fallback
    await new Promise(resolve => setTimeout(resolve, 1000));
    return { id: 'u1', pharmacyId: 'p1', email: email, name: 'صيدلية تجريبية (Mock)' };
  }

  // Simple query-based login (In production, use supabase.auth.signInWithPassword)
  const { data, error } = await supabase
    .from('pharmacies')
    .select('*')
    .eq('email', email)
    .single();

  if (error || !data) {
    console.error('Login error:', error);
    throw new Error('Invalid credentials');
  }

  // Mapping the database result to our User type
  return {
    id: data.id,
    pharmacyId: data.id, // In this simple schema, the user IS the pharmacy
    email: data.email,
    name: data.name
  };
};

export const getPharmacyInventory = async (pharmacyId: string): Promise<DashboardInventoryItem[]> => {
  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return [...mockInventory];
  }

  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicine_id,
      medicines (
        trade_name,
        scientific_name
      )
    `)
    .eq('pharmacy_id', pharmacyId);

  if (error) {
    console.error('Error fetching inventory:', error);
    throw error;
  }

  return data.map((item: any) => {
    // Handle potential array or object for joined relation
    const medicine = Array.isArray(item.medicines) ? item.medicines[0] : item.medicines;

    return {
      id: item.id,
      medicine_id: item.medicine_id,
      trade_name: medicine?.trade_name || 'Unknown',
      scientific_name: medicine?.scientific_name || 'Unknown',
      price: item.price,
      quantity: item.quantity
    };
  });
};

export const addInventoryItem = async (pharmacyId: string, item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => {
  if (!isSupabaseConfigured()) {
    console.warn('Adding item to mock inventory (will not persist)');
    await new Promise(resolve => setTimeout(resolve, 600));
    const newItem = { ...item, id: Math.random().toString(), medicine_id: Math.random().toString() };
    mockInventory = [newItem, ...mockInventory];
    return newItem;
  }

  try {
    // 1. Check if medicine exists, or create it
    // Use ilike for case-insensitive matching
    let { data: existingMedicines, error: searchError } = await supabase
      .from('medicines')
      .select('id')
      .ilike('trade_name', item.trade_name)
      .limit(1);

    if (searchError) {
      console.error('Error searching medicine:', searchError);
      throw searchError;
    }

    let medicineId = existingMedicines?.[0]?.id;

    if (!medicineId) {
      console.log('Medicine not found, creating new one...');
      const { data: newMedicine, error: createError } = await supabase
        .from('medicines')
        .insert({
          trade_name: item.trade_name,
          scientific_name: item.scientific_name
        })
        .select('id')
        .single();

      if (createError) {
        console.error('Error creating medicine:', createError);
        throw createError;
      }
      medicineId = newMedicine.id;
    }

    // 2. Add to inventory
    const { data: newInventory, error: invError } = await supabase
      .from('inventory')
      .insert({
        pharmacy_id: pharmacyId,
        medicine_id: medicineId,
        price: item.price,
        quantity: item.quantity
      })
      .select(`
        id,
        price,
        quantity,
        medicine_id,
        medicines (
          trade_name,
          scientific_name
        )
      `)
      .single();

    if (invError) {
      console.error('Error adding to inventory:', invError);
      throw invError;
    }

    // Safe extraction of nested data
    const medicineData = Array.isArray((newInventory as any).medicines) 
      ? (newInventory as any).medicines[0] 
      : (newInventory as any).medicines;

    const formattedItem: DashboardInventoryItem = {
      id: newInventory.id,
      medicine_id: newInventory.medicine_id,
      trade_name: medicineData?.trade_name || item.trade_name,
      scientific_name: medicineData?.scientific_name || item.scientific_name,
