export const addInventoryItem = async (pharmacyId: string, item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => {
  if (!isSupabaseConfigured()) {
    console.warn('Adding item to mock inventory (will not persist)');
    await new Promise(resolve => setTimeout(resolve, 600));
    const newItem = { ...item, id: Math.random().toString(), medicine_id: Math.random().toString() };
    mockInventory = [newItem, ...mockInventory];
    return newItem;
  }

  try {
    // 1. Check if medicine exists, or create it
    // Use ilike for case-insensitive matching
    let { data: existingMedicines, error: searchError } = await supabase
      .from('medicines')
      .select('id')
      .ilike('trade_name', item.trade_name)
      .limit(1);

    if (searchError) {
      console.error('Error searching medicine:', searchError);
      throw searchError;
    }

    let medicineId = existingMedicines?.[0]?.id;

    if (!medicineId) {
      console.log('Medicine not found, creating new one...');
      const { data: newMedicine, error: createError } = await supabase
        .from('medicines')
        .insert({
          trade_name: item.trade_name,
          scientific_name: item.scientific_name
        })
        .select('id')
        .single();

      if (createError) {
        console.error('Error creating medicine:', createError);
        throw createError;
      }
      medicineId = newMedicine.id;
    }

    // 2. Add to inventory
    const { data: newInventory, error: invError } = await supabase
      .from('inventory')
      .insert({
        pharmacy_id: pharmacyId,
        medicine_id: medicineId,
        price: item.price,
        quantity: item.quantity
      })
      .select(`
        id,
        price,
        quantity,
        medicine_id,
        medicines (
          trade_name,
          scientific_name
        )
      `)
      .single();

    if (invError) {
      console.error('Error adding to inventory:', invError);
      throw invError;
    }

    // Safe extraction of nested data
    const medicineData = Array.isArray((newInventory as any).medicines) 
      ? (newInventory as any).medicines[0] 
      : (newInventory as any).medicines;

    const formattedItem: DashboardInventoryItem = {
      id: newInventory.id,
      medicine_id: newInventory.medicine_id,
      trade_name: medicineData?.trade_name || item.trade_name,
      scientific_name: medicineData?.scientific_name || item.scientific_name,
      price: newInventory.price,
      quantity: newInventory.quantity
    };

    return formattedItem;

  } catch (err) {
    console.error('Transaction failed in addInventoryItem:', err);
    throw err;
  }
};

