             </button>

             {/* Stats */}
             <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 flex items-center gap-3 border border-white/10 min-w-[140px]">
               <div className="bg-white/20 p-2 rounded-lg">
                 <Package size={24} />
               </div>
               <div>
                 <p className="text-xs text-primary-100 font-bold">المخزون</p>
                 <p className="text-2xl font-black">{inventory.length}</p>
               </div>
             </div>
          </div>
