export const pharmacyLogin = async (email: string): Promise<User> => {
  logConnectionStatus();

  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 1000));
    return { 
      id: 'u1', 
      pharmacyId: 'p1', 
      email: email, 
      name: mockPharmacyDetails.name,
      address: mockPharmacyDetails.address 
    };
