    return [...mockInventory];
  }

  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicine_id,
      medicines (
        trade_name,
        scientific_name,
        barcode
      )
    `)
    .eq('pharmacy_id', pharmacyId);

