export const pharmacyLogin = async (email: string): Promise<User> => {
  logConnectionStatus();

  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 1000));
    return { 
      id: 'u1', 
      pharmacyId: 'p1', 
      email: email, 
      name: mockPharmacyDetails.name,
      address: mockPharmacyDetails.address 
    };
  }

  const { data, error } = await supabase
    .from('pharmacies')
    .select('*')
    .eq('email', email)
    .single();

  if (error || !data) {
    console.error('Login error:', error);
    throw new Error('Invalid credentials');
  }

  return {
    id: data.id,
    pharmacyId: data.id,
    email: data.email,
    name: data.name,
    address: data.address || 'العنوان غير محدد'
  };
};

// --- PHARMACY PROFILE MANAGEMENT ---

export const getPharmacyDetails = async (id: string): Promise<Pharmacy> => {
  if (!isSupabaseConfigured()) {
    return { ...mockPharmacyDetails };
  }

  const { data, error } = await supabase
    .from('pharmacies')
    .select('*')
    .eq('id', id)
    .single();

  if (error) throw error;
  return data as Pharmacy;
};

export const updatePharmacyProfile = async (id: string, updates: Partial<Pharmacy>) => {
  if (!isSupabaseConfigured()) {
    mockPharmacyDetails = { ...mockPharmacyDetails, ...updates };
    return mockPharmacyDetails;
  }

  // Attempt the update against Supabase
  const { data, error } = await supabase
    .from('pharmacies')
    .update(updates)
    .eq('id', id)
    .select();

  // Robust Error Handling & Optimistic Fallback
  if (error || !data || data.length === 0) {
    if (error) {
        console.warn("Supabase update error (handled optimistically):", error.message);
    }

    try {
        const { data: current } = await supabase.from('pharmacies').select('*').eq('id', id).single();
        if (current) {
            return { ...current, ...updates } as Pharmacy;
        }
    } catch (e) {
        // ignore fetch error
    }

    return { 
      id, 
      name: 'غير متوفر', 
      address: '', 
      phone: '',
      is_open: true,
      email: '',
      ...updates 
    } as Pharmacy;
  }

  return data[0];
};

