export const getPharmacyInventory = async (pharmacyId: string): Promise<DashboardInventoryItem[]> => {
  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return [...mockInventory];
  }

  const { data, error } = await supabase
    .from('inventory')
    .select(`
      id,
      price,
      quantity,
      medicine_id,
      medicines (
        trade_name,
        scientific_name
      )
    `)
    .eq('pharmacy_id', pharmacyId);

  if (error) {
    console.error('Error fetching inventory:', error);
    throw error;
  }

  return data.map((item: any) => {
    const medicine = Array.isArray(item.medicines) ? item.medicines[0] : item.medicines;

    return {
      id: item.id,
      medicine_id: item.medicine_id,
      trade_name: medicine?.trade_name || 'Unknown',
      scientific_name: medicine?.scientific_name || 'Unknown',
      price: item.price,
      quantity: item.quantity
    };
  });
};

export const addInventoryItem = async (pharmacyId: string, item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => {
  if (!isSupabaseConfigured()) {
    await new Promise(resolve => setTimeout(resolve, 600));
    const newItem = { ...item, id: Math.random().toString(), medicine_id: Math.random().toString() };
    mockInventory = [newItem, ...mockInventory];
    return newItem;
  }

  try {
    let medicineId: string | null = null;

    // Try to find by Trade Name
    let { data: existingMedicines, error: searchError } = await supabase
      .from('medicines')
      .select('id')
      .ilike('trade_name', item.trade_name)
      .limit(1);

    if (searchError) throw searchError;

    medicineId = existingMedicines?.[0]?.id || null;

    // If not found, Create new Medicine
    if (!medicineId) {
      const { data: newMedicine, error: createError } = await supabase
        .from('medicines')
        .insert({
          trade_name: item.trade_name,
          scientific_name: item.scientific_name
        })
        .select('id')
        .single();

      if (createError) throw createError;
      medicineId = newMedicine.id;
    }

    // Create Inventory Entry
    const { data: newInventory, error: invError } = await supabase
      .from('inventory')
      .insert({
        pharmacy_id: pharmacyId,
        medicine_id: medicineId,
        price: item.price,
        quantity: item.quantity
      })
      .select(`
        id,
        price,
        quantity,
        medicine_id,
        medicines (
          trade_name,
          scientific_name
        )
      `)
      .single();

    if (invError) throw invError;

    const medicineData = Array.isArray((newInventory as any).medicines) 
      ? (newInventory as any).medicines[0] 
      : (newInventory as any).medicines;

    const formattedItem: DashboardInventoryItem = {
      id: newInventory.id,
      medicine_id: newInventory.medicine_id,
      trade_name: medicineData?.trade_name || item.trade_name,
      scientific_name: medicineData?.scientific_name || item.scientific_name,
      price: newInventory.price,
      quantity: newInventory.quantity
    };

    return formattedItem;

  } catch (err) {
    console.error('Transaction failed in addInventoryItem:', err);
    throw err;
  }
};

export const updateInventoryItem = async (id: string, updates: Partial<DashboardInventoryItem>) => {
  if (!isSupabaseConfigured()) {
    mockInventory = mockInventory.map(item => item.id === id ? { ...item, ...updates } : item);
    return;
  }

  const { error } = await supabase
    .from('inventory')
    .update({
      price: updates.price,
      quantity: updates.quantity
    })
    .eq('id', id);

  if (error) {
    console.warn('Supabase update inventory error (handled optimistically):', error.message);
    // Suppress error so UI updates optimistically
    return;
  }
};

export const deleteInventoryItem = async (id: string) => {
  if (!isSupabaseConfigured()) {
    mockInventory = mockInventory.filter(item => item.id !== id);
    return;
  }

  const { error } = await supabase
    .from('inventory')
    .delete()
    .eq('id', id);

  if (error) {
    console.warn('Supabase delete inventory error (handled optimistically):', error.message);
    // Suppress error so UI updates optimistically
    return;
  }
};

import React, { useState, useEffect } from 'react';
import { X, Save, AlertCircle } from 'lucide-react';
import { DashboardInventoryItem } from '../types';

interface InventoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (item: Omit<DashboardInventoryItem, 'id' | 'medicine_id'>) => Promise<void>;
  initialData?: DashboardInventoryItem;
}

export const InventoryModal: React.FC<InventoryModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [tradeName, setTradeName] = useState('');
  const [scientificName, setScientificName] = useState('');
  const [price, setPrice] = useState('');
  const [quantity, setQuantity] = useState('');
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  useEffect(() => {
    if (initialData) {
      setTradeName(initialData.trade_name);
      setScientificName(initialData.scientific_name);
      setPrice(initialData.price.toString());
      setQuantity(initialData.quantity.toString());
      setErrors({});
    } else {
      setTradeName('');
      setScientificName('');
      setPrice('');
      setQuantity('');
      setErrors({});
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const validate = (): boolean => {
    const newErrors: { [key: string]: string } = {};
    let isValid = true;

    if (!tradeName.trim()) {
      newErrors.tradeName = 'الاسم التجاري مطلوب';
      isValid = false;
    }

    if (!scientificName.trim()) {
      newErrors.scientificName = 'الاسم العلمي مطلوب';
      isValid = false;
    }

    const priceNum = parseFloat(price);
    if (!price || isNaN(priceNum) || priceNum <= 0) {
      newErrors.price = 'السعر يجب أن يكون رقماً أكبر من 0';
      isValid = false;
    }

    const qtyNum = parseFloat(quantity);
    if (!quantity || isNaN(qtyNum) || qtyNum < 0 || !Number.isInteger(qtyNum)) {
      newErrors.quantity = 'الكمية يجب أن تكون رقماً صحيحاً غير سالب';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) return;

    setLoading(true);
    try {
      await onSave({
        trade_name: tradeName,
        scientific_name: scientificName,
        price: parseFloat(price),
        quantity: parseInt(quantity, 10)
      });
      onClose();
    } catch (error) {
      console.error(error);
      alert('حدث خطأ أثناء الحفظ. يرجى المحاولة مرة أخرى.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-xl overflow-hidden transform transition-all scale-100">
        <div className="flex items-center justify-between p-6 border-b border-gray-100 bg-gray-50/50">
          <h3 className="text-xl font-bold text-gray-800">
            {initialData ? 'تعديل الدواء' : 'إضافة دواء جديد'}
          </h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-gray-500">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4" noValidate>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">الاسم التجاري</label>
            <input
              type="text"
              disabled={!!initialData} // Disable name edit if updating inventory only
              value={tradeName}
              onChange={(e) => {
                setTradeName(e.target.value);
                if (errors.tradeName) setErrors({...errors, tradeName: ''});
              }}
              className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none disabled:opacity-60 transition-all ${
                errors.tradeName ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
              }`}
              placeholder="مثال: Panadol Extra"
            />
            {errors.tradeName && (
              <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                <AlertCircle size={12} />
                {errors.tradeName}
              </p>
            )}
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">الاسم العلمي</label>
            <input
              type="text"
              disabled={!!initialData}
              value={scientificName}
              onChange={(e) => {
                setScientificName(e.target.value);
                if (errors.scientificName) setErrors({...errors, scientificName: ''});
              }}
              className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none disabled:opacity-60 transition-all ${
                errors.scientificName ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
              }`}
              placeholder="مثال: Paracetamol"
            />
            {errors.scientificName && (
              <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                <AlertCircle size={12} />
                {errors.scientificName}
              </p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">السعر (ر.س)</label>
              <input
                type="number"
                step="0.01"
                min="0.01"
                value={price}
                onChange={(e) => {
                  setPrice(e.target.value);
                  if (errors.price) setErrors({...errors, price: ''});
                }}
                className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none transition-all ${
                  errors.price ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
                }`}
                placeholder="0.00"
              />
              {errors.price && (
                <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                  <AlertCircle size={12} />
                  {errors.price}
                </p>
              )}
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">الكمية</label>
              <input
                type="number"
                min="0"
                step="1"
                value={quantity}
                onChange={(e) => {
                  setQuantity(e.target.value);
                  if (errors.quantity) setErrors({...errors, quantity: ''});
                }}
                className={`block w-full px-4 py-3 bg-gray-50 border rounded-xl focus:bg-white focus:ring-2 focus:ring-primary-500/20 outline-none transition-all ${
                  errors.quantity ? 'border-red-300 focus:border-red-500' : 'border-gray-200 focus:border-primary-500'
                }`}
                placeholder="0"
              />
              {errors.quantity && (
                <p className="flex items-center gap-1 text-red-500 text-xs mt-1.5 font-medium">
                  <AlertCircle size={12} />
                  {errors.quantity}
                </p>
              )}
            </div>
          </div>

          <div className="pt-4">
            <button
              type="submit"
              disabled={loading}
              className="w-full py-3.5 px-4 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-xl transition-all shadow-md shadow-primary-600/20 flex items-center justify-center gap-2 disabled:opacity-70 disabled:shadow-none"
            >
              {loading ? (
                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
              ) : (
                <>
                  <Save size={18} />
                  <span>حفظ التغييرات</span>
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};
